如何从0到1的复现LevelDB？ 🧩 基本数据结构​ 以下数据结构属于LevelDB的基础组件，耦合度较低，便于独立实现和测试。需要注意的是，Slice是一种非拥有（non-owning）类型的切片，因此在使用时需关注其生命周期。SkipList的实现可以参考[1]提供的经典论文。 Slice 不拥有数据，只是引用 支持字符串和二进制数据 提供基本的比较、查找操作 SkipList MemTable的核心数据结构 实现内存中的有序键值存储 LRU Cache 用于缓存从磁盘中读取的sstable block和table metadata Bloom Filter 用于跳过不必要的SSTable查找 减少磁盘访问次数，提高读性能 crc32校验和 定义在util/crc32c.h 12345678910111213141516171819202122232425// Return the crc32c of concat(A, data[0,n-1]) where init_crc is the// crc32c of some string A. Extend() is often used to maintain the// crc32c of a stream of data.uint32_t Extend(uint32_t init_crc, const char* data, size_t n);// Return the crc32c of data[0,n-1]inline uint32_t Value(const char* data, size_t n) &#123; return Extend(0, data, n); &#125;static const uint32_t kMaskDelta = 0xa282ead8ul;// Return a masked representation of crc.//// Motivation: it is problematic to compute the CRC of a string that// contains embedded CRCs. Therefore we recommend that CRCs stored// somewhere (e.g., in files) should be masked before being stored.inline uint32_t Mask(uint32_t crc) &#123; // Rotate right by 15 bits and add a constant. return ((crc &gt;&gt; 15) | (crc &lt;&lt; 17)) + kMaskDelta;&#125;// Return the crc whose masked representation is masked_crc.inline uint32_t Unmask(uint32_t masked_crc) &#123; uint32_t rot = masked_crc - kMaskDelta; return ((rot &gt;&gt; 17) | (rot &lt;&lt; 15));&#125; 对整数编码 定义在util/coding.h 123456789101112// Standard Put... routines append to a stringvoid PutFixed32(std::string* dst, uint32_t value);void PutFixed64(std::string* dst, uint64_t value);void PutVarint32(std::string* dst, uint32_t value);void PutVarint64(std::string* dst, uint64_t value);void PutLengthPrefixedSlice(std::string* dst, const Slice&amp; value);// Standard Get... routines parse a value from the beginning of a Slice// and advance the slice past the parsed value.bool GetVarint32(Slice* input, uint32_t* value);bool GetVarint64(Slice* input, uint64_t* value);bool GetLengthPrefixedSlice(Slice* input, Slice* result); 🧱 核心类​ 有了上述辅助类之后，通过理解数据写入流程了解其它核心的类。当我们调用Put(key, value)的时候，其中key，value的类型都是Slice。在WriteBatch中，key和value被重新组织成以下方式： 123456789101112Status DB::Put(const WriteOptions&amp; opt, const Slice&amp; key, const Slice&amp; value) &#123; WriteBatch batch; batch.Put(key, value); return Write(opt, &amp;batch);&#125;void WriteBatch::Put(const Slice&amp; key, const Slice&amp; value) &#123; WriteBatchInternal::SetCount(this, WriteBatchInternal::Count(this) + 1); rep_.push_back(static_cast&lt;char&gt;(kTypeValue)); PutLengthPrefixedSlice(&amp;rep_, key); PutLengthPrefixedSlice(&amp;rep_, value);&#125; 写入逻辑 ​ 在LevelDB中，writers_是一个写请求队列，多个线程可能同时调用DBImpl::Write(...)方法，但只有最前面的那个 Writer（writers_.front()）有资格执行写入操作。其他线程只能等待前面的写入完成。 1234567891011121314151617Status DBImpl::Write(const WriteOptions&amp; options, WriteBatch* updates) &#123; Writer w(&amp;mutex_); w.batch = updates; w.sync = options.sync; w.done = false; MutexLock l(&amp;mutex_); writers_.push_back(&amp;w); while (!w.done &amp;&amp; &amp;w != writers_.front()) &#123; w.cv.Wait(); &#125; if (w.done) &#123; return w.status; &#125; ...&#125; 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556// May temporarily unlock and wait.Status status = MakeRoomForWrite(updates == nullptr);uint64_t last_sequence = versions_-&gt;LastSequence();Writer* last_writer = &amp;w;if (status.ok() &amp;&amp; updates != nullptr) &#123; // nullptr batch is for compactions WriteBatch* write_batch = BuildBatchGroup(&amp;last_writer); WriteBatchInternal::SetSequence(write_batch, last_sequence + 1); last_sequence += WriteBatchInternal::Count(write_batch); // Add to log and apply to memtable. We can release the lock // during this phase since &amp;w is currently responsible for logging // and protects against concurrent loggers and concurrent writes // into mem_. &#123; mutex_.Unlock(); status = log_-&gt;AddRecord(WriteBatchInternal::Contents(write_batch)); bool sync_error = false; if (status.ok() &amp;&amp; options.sync) &#123; status = logfile_-&gt;Sync(); if (!status.ok()) &#123; sync_error = true; &#125; &#125; if (status.ok()) &#123; status = WriteBatchInternal::InsertInto(write_batch, mem_); &#125; mutex_.Lock(); if (sync_error) &#123; // The state of the log file is indeterminate: the log record we // just added may or may not show up when the DB is re-opened. // So we force the DB into a mode where all future writes fail. RecordBackgroundError(status); &#125; &#125; if (write_batch == tmp_batch_) tmp_batch_-&gt;Clear(); versions_-&gt;SetLastSequence(last_sequence);&#125;while (true) &#123; Writer* ready = writers_.front(); writers_.pop_front(); if (ready != &amp;w) &#123; ready-&gt;status = status; ready-&gt;done = true; ready-&gt;cv.Signal(); &#125; if (ready == last_writer) break;&#125;// Notify new head of write queueif (!writers_.empty()) &#123; writers_.front()-&gt;cv.Signal();&#125;return status; 🧠 MakeRoomForWrite()逻辑 后台有错误，不能继续写 1234if (!bg_error_.ok()) &#123; s = bg_error_; break;&#125; 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677// REQUIRES: mutex_ is held// REQUIRES: this thread is currently at the front of the writer queueStatus DBImpl::MakeRoomForWrite(bool force) &#123; mutex_.AssertHeld(); assert(!writers_.empty()); bool allow_delay = !force; Status s; while (true) &#123; if (!bg_error_.ok()) &#123; // Yield previous error s = bg_error_; break; &#125; else if (allow_delay &amp;&amp; versions_-&gt;NumLevelFiles(0) &gt;= config::kL0_SlowdownWritesTrigger) &#123; // We are getting close to hitting a hard limit on the number of // L0 files. Rather than delaying a single write by several // seconds when we hit the hard limit, start delaying each // individual write by 1ms to reduce latency variance. Also, // this delay hands over some CPU to the compaction thread in // case it is sharing the same core as the writer. mutex_.Unlock(); env_-&gt;SleepForMicroseconds(1000); allow_delay = false; // Do not delay a single write more than once mutex_.Lock(); &#125; else if (!force &amp;&amp; (mem_-&gt;ApproximateMemoryUsage() &lt;= options_.write_buffer_size)) &#123; // There is room in current memtable break; &#125; else if (imm_ != nullptr) &#123; // We have filled up the current memtable, but the previous // one is still being compacted, so we wait. Log(options_.info_log, &quot;Current memtable full; waiting...
&quot;); background_work_finished_signal_.Wait(); &#125; else if (versions_-&gt;NumLevelFiles(0) &gt;= config::kL0_StopWritesTrigger) &#123; // There are too many level-0 files. Log(options_.info_log, &quot;Too many L0 files; waiting...
&quot;); background_work_finished_signal_.Wait(); &#125; else &#123; // Attempt to switch to a new memtable and trigger compaction of old assert(versions_-&gt;PrevLogNumber() == 0); uint64_t new_log_number = versions_-&gt;NewFileNumber(); WritableFile* lfile = nullptr; s = env_-&gt;NewWritableFile(LogFileName(dbname_, new_log_number), &amp;lfile); if (!s.ok()) &#123; // Avoid chewing through file number space in a tight loop. versions_-&gt;ReuseFileNumber(new_log_number); break; &#125; delete log_; s = logfile_-&gt;Close(); if (!s.ok()) &#123; // We may have lost some data written to the previous log file. // Switch to the new log file anyway, but record as a background // error so we do not attempt any more writes. // // We could perhaps attempt to save the memtable corresponding // to log file and suppress the error if that works, but that // would add more complexity in a critical code path. RecordBackgroundError(s); &#125; delete logfile_; logfile_ = lfile; logfile_number_ = new_log_number; log_ = new log::Writer(lfile); imm_ = mem_; has_imm_.store(true, std::memory_order_release); mem_ = new MemTable(internal_comparator_); mem_-&gt;Ref(); force = false; // Do not force another compaction if have room MaybeScheduleCompaction(); &#125; &#125; return s;&#125; ✅ 那是谁调用 writers_ 中真正的写入逻辑呢？👉 是队列头部的 Writer对应的线程 —— 也就是当前调用 Write(...) 的线程自己在处理！ LevelDB 没有专门的写线程或后台线程来做这件事。 具体来说： 多个线程同时调用 Write(...)，都往 writers_ 加入自己的 Writer。 每个线程加完以后判断自己是不是头部： 1234567cpp复制编辑while (!w.done &amp;&amp; &amp;w != writers_.front()) &#123; w.cv.Wait();&#125; 只有最前面的那个线程会继续执行主写入逻辑，包括： 构建批次（BuildBatchGroup()）； 写入 WAL（log_-&gt;AddRecord(...)）； 同步磁盘（logfile_-&gt;Sync()）； 写入 MemTable； 更新序列号。 写完后，它会负责把后续所有批次的 Writer.status 和 Writer.done 设置好，并通过 cv.Signal() 依次唤醒后面的写线程。 🔁 举个例子假设有三个线程同时写入： 线程 操作 是否执行写入 T1 调用 Write()，加入队列 ✅ 是第一个，执行写入 T2 调用 Write()，加入队列 ⏸ 等待唤醒 T3 调用 Write()，加入队列 ⏸ 等待唤醒 T1 执行完写入，会把 T2 和 T3 的 done = true; status = T1的写入状态; 并唤醒它们。 T2 和 T3 醒来发现 done = true，返回状态，整个流程结束。 测试代码 1234567891011121314151617181920212223242526272829303132333435#include &quot;leveldb/db.h&quot;#include &quot;leveldb/env.h&quot;#include &lt;iostream&gt;#include &lt;fstream&gt;int main() &#123; leveldb::DB* db; leveldb::Options options; options.create_if_missing = true; leveldb::Status status = leveldb::DB::Open(options, &quot;/tmp/testdb&quot;, &amp;db); assert(status.ok()); leveldb::WriteOptions write_options; for (int i = 0; i &lt; 1000; ++i) &#123; db-&gt;Put(write_options, &quot;key&quot; + std::to_string(i), &quot;value&quot; + std::to_string(i)); &#125; delete db; // 查看CURRENT文件内容 std::ifstream current(&quot;/tmp/testdb/CURRENT&quot;); std::string manifest_name; std::getline(current, manifest_name); std::cout &lt;&lt; &quot;CURRENT points to: &quot; &lt;&lt; manifest_name &lt;&lt; &quot;
&quot;; // 打印 MANIFEST文件内容 std::ifstream manifest(&quot;/tmp/testdb/&quot; + manifest_name); std::string line; while (std::getline(manifest, line)) &#123; std::cout &lt;&lt; line &lt;&lt; &quot;
&quot;; &#125; return 0;&#125; 结果 数据没有被刷新到磁盘 1234567$ ls -l /tmp/testdbtotal 48-rw-r--r-- 1 gc gc 35787 6月 4 09:34 000003.log-rw-r--r-- 1 gc gc 16 6月 4 09:34 CURRENT-rw-r--r-- 1 gc gc 0 6月 4 09:34 LOCK-rw-r--r-- 1 gc gc 149 6月 4 09:34 LOG-rw-r--r-- 1 gc gc 50 6月 4 09:34 MANIFEST-000002 将写入次数调整到10000 123456789$ ls -l /tmp/testdbtotal 4612-rw-r--r-- 1 gc gc 3280376 6月 4 09:44 000003.log-rw-r--r-- 1 gc gc 698227 6月 4 09:44 000004.log-rw-r--r-- 1 gc gc 726518 6月 4 09:44 000005.ldb-rw-r--r-- 1 gc gc 16 6月 4 09:44 CURRENT-rw-r--r-- 1 gc gc 0 6月 4 09:44 LOCK-rw-r--r-- 1 gc gc 295 6月 4 09:44 LOG-rw-r--r-- 1 gc gc 50 6月 4 09:44 MANIFEST-000002 将写入次数调整到5000000 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253$ ls -l /tmp/testdbtotal 58260-rw-r--r-- 1 gc gc 2127350 6月 4 09:51 000058.ldb-rw-r--r-- 1 gc gc 2127144 6月 4 09:51 000061.ldb-rw-r--r-- 1 gc gc 708939 6月 4 09:51 000066.ldb-rw-r--r-- 1 gc gc 711416 6月 4 09:51 000068.ldb-rw-r--r-- 1 gc gc 2123417 6月 4 09:51 000069.ldb-rw-r--r-- 1 gc gc 707350 6月 4 09:51 000071.ldb-rw-r--r-- 1 gc gc 2123841 6月 4 09:51 000072.ldb-rw-r--r-- 1 gc gc 2123556 6月 4 09:51 000073.ldb-rw-r--r-- 1 gc gc 357437 6月 4 09:51 000074.ldb-rw-r--r-- 1 gc gc 2126335 6月 4 09:51 000095.ldb-rw-r--r-- 1 gc gc 2126702 6月 4 09:51 000098.ldb-rw-r--r-- 1 gc gc 707157 6月 4 09:51 000100.ldb-rw-r--r-- 1 gc gc 2126680 6月 4 09:51 000101.ldb-rw-r--r-- 1 gc gc 711202 6月 4 09:51 000103.ldb-rw-r--r-- 1 gc gc 707644 6月 4 09:51 000105.ldb-rw-r--r-- 1 gc gc 2126745 6月 4 09:51 000106.ldb-rw-r--r-- 1 gc gc 711015 6月 4 09:51 000108.ldb-rw-r--r-- 1 gc gc 2127690 6月 4 09:51 000109.ldb-rw-r--r-- 1 gc gc 707161 6月 4 09:51 000111.ldb-rw-r--r-- 1 gc gc 2127320 6月 4 09:51 000112.ldb-rw-r--r-- 1 gc gc 711363 6月 4 09:51 000114.ldb-rw-r--r-- 1 gc gc 707847 6月 4 09:51 000117.ldb-rw-r--r-- 1 gc gc 711135 6月 4 09:51 000119.ldb-rw-r--r-- 1 gc gc 707174 6月 4 09:51 000121.ldb-rw-r--r-- 1 gc gc 711654 6月 4 09:51 000123.ldb-rw-r--r-- 1 gc gc 708062 6月