转载：asio的异步与线程模型解析 🧩 概要​ 本文使用的asio版本1.76.0从github获取，老版本中有一个很重要的结构叫做io_service，新版本中改成了io_context。下面主要通过C++14下的一个异步的例子分析asio的线程模型，其代码结构比较复杂，时间有限不能分析的很详细，只是做大体结构分析。 🎯 正文asio的线程模型和异步的调用如下图 程序以一个io_context为核心，其下有一个scheduler对象（调度器），scheduler下面放着一个（op_queue_）任务队列，一个epoll_fd，执行io_context.run()的时候，开始一个循环去竞争消费任务队列；任务队列有两种任务，一种是epoll任务，就是去做一次epoll_wait，还有一种任务是执行回调用函数；当使用一个异步调用的时候，本质就是往reactor中添加一个fd的event，将其回调保存进去event.data中，当执行epoll_wait()监听到该event事件后，取出该fd对应的callback放入到任务队列（op_queue），由不同的线程去竞争消费； 拿官方的例子简单分析这个流程，该例子来源于asio/src/examples/cpp14/echo/async_tcp_echo_server.cpp， 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106#include &lt;cstdlib&gt;#include &lt;iostream&gt;#include &lt;memory&gt;#include &lt;utility&gt;#include &lt;asio/ts/buffer.hpp&gt;#include &lt;asio/ts/internet.hpp&gt;using asio::ip::tcp;class session : public std::enable_shared_from_this&lt;session&gt;&#123;public: session(tcp::socket socket) : socket_(std::move(socket)) &#123; &#125; void start() &#123; do_read(); &#125;private: void do_read() &#123; auto self(shared_from_this()); socket_.async_read_some(asio::buffer(data_, max_length), [this, self](std::error_code ec, std::size_t length) &#123; if (!ec) &#123; do_write(length); &#125; &#125;); &#125; void do_write(std::size_t length) &#123; auto self(shared_from_this()); asio::async_write(socket_, asio::buffer(data_, length), [this, self](std::error_code ec, std::size_t /*length*/) &#123; if (!ec) &#123; do_read(); &#125; &#125;); &#125; tcp::socket socket_; enum &#123; max_length = 1024 &#125;; char data_[max_length];&#125;;class server&#123;public: server(asio::io_context&amp; io_context, short port) : acceptor_(io_context, tcp::endpoint(tcp::v4(), port)), socket_(io_context) &#123; do_accept(); &#125;private: void do_accept() &#123; acceptor_.async_accept(socket_, [this](std::error_code ec) &#123; if (!ec) &#123; std::make_shared&lt;session&gt;(std::move(socket_))-&gt;start(); &#125; do_accept(); &#125;); &#125; tcp::acceptor acceptor_; tcp::socket socket_;&#125;;int main(int argc, char* argv[])&#123; try &#123; if (argc != 2) &#123; std::cerr &lt;&lt; &quot;Usage: async_tcp_echo_server &lt;port&gt;
&quot;; return 1; &#125; asio::io_context io_context; server s(io_context, std::atoi(argv[1])); io_context.run(); &#125; catch (std::exception&amp; e) &#123; std::cerr &lt;&lt; &quot;Exception: &quot; &lt;&lt; e.what() &lt;&lt; &quot;
&quot;; &#125; return 0;&#125; 代码很长，这里重点分析io_context.run();和acceptor_.async_accept()以分析其线程模型和异步，main()创建了io_context和server，server构造函数中创建了acceptor和socket，然后执行一个异步async_accept，将一个lambda函数注册进去，accept事件发生了，进行accept创建客户端的socket后，调用该lambda回调去处理新accept的socket； 然后执行io_content.run()，做一个循环监听。 程序的调用图如下所示 如图上标黄，主要分成3个比较重要的部分： 第一部分是acceptor的创建，放入epoll进行监听，在server的构造函数中开始构造acceptor： 12345678910111213141516class server&#123;public: server(asio::io_context&amp; io_context, short port) : acceptor_(io_context, tcp::endpoint(tcp::v4(), port)), // 构造acceptor socket_(io_context) &#123; do_accept(); &#125;private: ...... tcp::acceptor acceptor_; tcp::socket socket_;&#125;; tcp::acceptor其实是一个typedef，构造的class basic_socket_acceptor&lt;tcp&gt;。在这里，除了看到了熟悉的bind和listen，重要的是open。 12345678910111213141516171819202122232425262728// asio/basic_socket_acceptor.hppdetail::io_object_impl&lt; detail::reactive_socket_service&lt;Protocol&gt;, Executor&gt; impl_;template &lt;typename ExecutionContext&gt;basic_socket_acceptor(ExecutionContext&amp; context, const endpoint_type&amp; endpoint, bool reuse_addr = true, typename constraint&lt; is_convertible&lt;ExecutionContext&amp;, execution_context&amp;&gt;::value &gt;::type = 0) : impl_(0, 0, context)&#123; asio::error_code ec; const protocol_type protocol = endpoint.protocol(); impl_.get_service().open(impl_.get_implementation(), protocol, ec); // open asio::detail::throw_error(ec, &quot;open&quot;); if (reuse_addr) &#123; impl_.get_service().set_option(impl_.get_implementation(), socket_base::reuse_address(true), ec); asio::detail::throw_error(ec, &quot;set_option&quot;); &#125; impl_.get_service().bind(impl_.get_implementation(), endpoint, ec); // bind asio::detail::throw_error(ec, &quot;bind&quot;); impl_.get_service().listen(impl_.get_implementation(), // listen socket_base::max_listen_connections, ec); asio::detail::throw_error(ec, &quot;listen&quot;);&#125; 这里涉及到impl_的初始化。IoObjectService服务通常是一个单例。 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556// asio/detail/io_object_impl.hpptemplate &lt;typename IoObjectService, typename Executor = io_context::executor_type&gt;class io_object_impl &#123; // Construct an I/O object using an execution context. template &lt;typename ExecutionContext&gt; explicit io_object_impl(int, int, ExecutionContext&amp; context) : service_(&amp;asio::use_service&lt;IoObjectService&gt;(context)), executor_(context.get_executor()) &#123; service_-&gt;construct(implementation_); &#125;&#125;;// asio/detail/reactive_socket_service.hpptemplate &lt;typename Protocol&gt;class reactive_socket_service : public execution_context_service_base&lt;reactive_socket_service&lt;Protocol&gt;&gt;, public reactive_socket_service_base &#123; // The implementation type of the socket. struct implementation_type : reactive_socket_service_base::base_implementation_type &#123; // Default constructor. implementation_type() : protocol_(endpoint_type().protocol()) &#123;&#125; // The protocol associated with the socket. protocol_type protocol_; &#125;;&#125;;// asio/detail/reactive_socket_service_base.hppclass reactive_socket_service_base&#123;public: // The implementation type of the socket. struct base_implementation_type &#123; // The native socket representation. socket_type socket_; // The current state of the socket. socket_ops::state_type state_; // Per-descriptor data used by the reactor. reactor::per_descriptor_data reactor_data_; &#125;;&#125;;void reactive_socket_service_base::construct( reactive_socket_service_base::base_implementation_type&amp; impl)&#123; impl.socket_ = invalid_socket; impl.state_ = 0; impl.reactor_data_ = reactor::per_descriptor_data();&#125; 在Unix/Linux中，construct()方法初始化impl的成员： impl.socket_：底层socket的文件描述符。 impl.state_：状态标志（如阻塞&#x2F;非阻塞、流式&#x2F;数据报协议）。 open()是do_open()的封装，作用是创建一个socket，并为其添加相应的epoll event事件。 123456789// Open a new socket implementation.asio::error_code open(implementation_type&amp; impl, const protocol_type&amp; protocol, asio::error_code&amp; ec)&#123; if (!do_open(impl, protocol.family(), protocol.type(), protocol.protocol(), ec)) impl.protocol_ = protocol; return ec;&#125; 以下是do_open()，socket_holder创建了server端的socket，register_descriptor()将该socket注册到了该io_context上的epoll fd上。 1234567891011121314151617181920212223242526272829303132asio::error_code reactive_socket_service_base::do_open( reactive_socket_service_base::base_implementation_type&amp; impl, int af, int type, int protocol, asio::error_code&amp; ec)&#123; if (is_open(impl)) &#123; ec = asio::error::already_open; return ec; &#125; socket_holder sock(socket_ops::socket(af, type, protocol, ec)); // 创建了socket if (sock.get() == invalid_socket) return ec; // 注册到epoll上 if (int err = reactor_.register_descriptor(sock.get(), impl.reactor_data_)) &#123; ec = asio::error_code(err, asio::error::get_system_category()); return ec; &#125; impl.socket_ = sock.release(); switch (type) &#123; case SOCK_STREAM: impl.state_ = socket_ops::stream_oriented; break; case SOCK_DGRAM: impl.state_ = socket_ops::datagram_oriented; break; default: impl.state_ = 0; break; &#125; ec = asio::error_code(); return ec;&#125; 1234567891011121314151617181920212223242526272829303132333435363738394041// asio/detail/impl/epoll_reactor.hppint epoll_reactor::register_descriptor(socket_type descriptor, epoll_reactor::per_descriptor_data&amp; descriptor_data)&#123; descriptor_data = allocate_descriptor_state(); ASIO_HANDLER_REACTOR_REGISTRATION(( context(), static_cast&lt;uintmax_t&gt;(descriptor), reinterpret_cast&lt;uintmax_t&gt;(descriptor_data))); &#123; mutex::scoped_lock descriptor_lock(descriptor_data-&gt;mutex_); descriptor_data-&gt;reactor_ = this; descriptor_data-&gt;descriptor_ = descriptor; descriptor_data-&gt;shutdown_ = false; for (int i = 0; i &lt; max_ops; ++i) descriptor_data-&gt;try_speculative_[i] = true; &#125; epoll_event ev = &#123; 0, &#123; 0 &#125; &#125;; ev.events = EPOLLIN | EPOLLERR | EPOLLHUP | EPOLLPRI | EPOLLET; descriptor_data-&gt;registered_events_ = ev.events; ev.data.ptr = descriptor_data; int result = epoll_ctl(epoll_fd_, EPOLL_CTL_ADD, descriptor, &amp;ev); if (result != 0) &#123; if (errno == EPERM) &#123; // This file descriptor type is not supported by epoll. However, if it is // a regular file then operations on it will not block. We will allow // this descriptor to be used and fail later if an operation on it would // otherwise require a trip through the reactor. descriptor_data-&gt;registered_events_ = 0; return 0; &#125; return errno; &#125; return 0;&#125; 到此，一个完整的server的socket就创建完毕，并且进行bind和listen，并放入到epoll中。 第二个重要的部分是async_accept()这个异步的运行。 1234567891011121314151617181920class server&#123;private: void do_accept() &#123; acceptor_.async_accept(socket_, // 执行异步调用 [this](std::error_code ec) &#123; if (!ec) &#123; std::make_shared&lt;session&gt;(std::move(socket_))-&gt;start(); &#125; do_accept(); &#125;); &#125; tcp::acceptor acceptor_; tcp::socket socket_;&#125;; 使用第一部分创建好的acceptor进行async_accept()后，来到一个看起来很复杂的模板函数。 12345678910111213141516template &lt;typename Protocol1, typename Executor1, ASIO_COMPLETION_TOKEN_FOR(void (asio::error_code)) AcceptHandler ASIO_DEFAULT_COMPLETION_TOKEN_TYPE(executor_type)&gt;ASIO_INITFN_AUTO_RESULT_TYPE(AcceptHandler, void (asio::error_code))async_accept(basic_socket&lt;Protocol1, Executor1&gt;&amp; peer, ASIO_MOVE_ARG(AcceptHandler) handler ASIO_DEFAULT_COMPLETION_TOKEN(executor_type), typename constraint&lt; is_convertible&lt;Protocol, Protocol1&gt;::value &gt;::type = 0)&#123; return async_initiate&lt;AcceptHandler, void (asio::error_code)&gt;( initiate_async_accept(this), handler, &amp;peer, static_cast&lt;endpoint_type*&gt;(0));&#125; 不用太在意头，看看async_initiate()做了啥？ 12345678910111213141516171819template &lt;typename CompletionToken, ASIO_COMPLETION_SIGNATURE Signature, typename Initiation, typename... Args&gt;inline typename constraint&lt; !detail::async_result_has_initiate_memfn&lt;CompletionToken, Signature&gt;::value, ASIO_INITFN_RESULT_TYPE(CompletionToken, Signature)&gt;::typeasync_initiate(ASIO_MOVE_ARG(Initiation) initiation, ASIO_NONDEDUCED_MOVE_ARG(CompletionToken) token, ASIO_MOVE_ARG(Args)... args)&#123; async_completion&lt;CompletionToken, Signature&gt; completion(token); ASIO_MOVE_CAST(Initiation)(initiation)( ASIO_MOVE_CAST(ASIO_HANDLER_TYPE(CompletionToken, Signature))(completion.completion_handler), ASIO_MOVE_CAST(Args)(args)...); return completion.result.get();&#125; 来到了一个更加复杂的模板函数，但是函数体只有两三句话，发现其调用的时候模板类Initiation的operator()，这个模板类是class initiate_async_accept，其对应的operator()如下： 1234567891011121314template &lt;typename AcceptHandler, typename Protocol1, typename Executor1&gt;void operator()(ASIO_MOVE_ARG(AcceptHandler) handler, basic_socket&lt;Protocol1, Executor1&gt;* peer, endpoint_type* peer_endpoint) const&#123; // If you get an error on the following line it means that your handler // does not meet the documented type requirements for a AcceptHandler. ASIO_ACCEPT_HANDLER_CHECK(AcceptHandler, handler) type_check; detail::non_const_lvalue&lt;AcceptHandler&gt; handler2(handler); self_-&gt;impl_.get_service().async_accept( self_-&gt;impl_.get_implementation(), *peer, peer_endpoint, handler2.value, self_-&gt;impl_.get_executor());&#125; 核心代码self_-&gt;impl_.get_service().async_accept(...)，这个impl_.get_service()获取到的是class reactive_socket_service，在basic_socket_acceptor中可以看到 1234class basic_socket_acceptor : public socket_base&#123; detail::io_object_impl&lt;detail::reactive_socket_service&lt;Protocol&gt;, Executor&gt; impl_;&#125; 为此，找到了async_accept()的实现如下，看起来很长，但重点在最后的start_accept_op()。 12345678910111213141516171819202122// Start an asynchronous accept. The peer and peer_endpoint objects must be// valid until the accept&#x27;s handler is invoked.template &lt;typename Socket, typename Handler, typename IoExecutor&gt;void async_accept(implementation_type&amp; impl, Socket&amp; peer, endpoint_type* peer_endpoint, Handler&amp; handler, const IoExecutor&amp; io_ex)&#123; bool is_continuation = asio_handler_cont_helpers::is_continuation(handler); // Allocate and construct an operation to wrap the handler. typedef reactive_socket_accept_op&lt;Socket, Protocol, Handler, IoExecutor&gt; op; typename op::ptr p = &#123; asio::detail::addressof(handler), op::ptr::allocate(handler), 0 &#125;; p.p = new (p.v) op(success_ec_, impl.socket_, impl.state_, peer, impl.protocol_, peer_endpoint, handler, io_ex); ASIO_HANDLER_CREATION((reactor_.context(), *p.p, &quot;socket&quot;, &amp;impl, impl.socket_, &quot;async_accept&quot;)); start_accept_op(impl, p.p, is_continuation, peer.is_open()); // 开始accept 的操作 p.v = p.p = 0;&#125; start_accept_op()调用了start_op() 123456789101112void reactive_socket_service_base::start_accept_op( reactive_socket_service_base::base_implementation_type&amp; impl, reactor_op* op, bool is_continuation, bool peer_is_open)&#123; if (!peer_is_open) start_op(impl, reactor::read_op, op, is_continuation, true, false); else &#123; op-&gt;ec_ = asio::error::already_open; reactor_.post_immediate_completion(op, is_continuation); &#125;&#125; 而start_op()中调用的是reactor.start_op() 12345678910111213141516171819void reactive_socket_service_base::start_op( reactive_socket_service_base::base_implementation_type&amp; impl, int op_type, reactor_op* op, bool is_continuation, bool is_non_blocking, bool noop)&#123; if (!noop) &#123; if ((impl.state_ &amp; socket_ops::non_blocking) || socket_ops::set_internal_non_blocking( impl.socket_, impl.state_, true, op-&gt;ec_)) &#123; reactor_.start_op(op_type, impl.socket_, impl.reactor_data_, op, is_continuation, is_non_blocking); //调用reactor的start_op() return; &#125; &#125; reactor_.post_immediate_completion(op, is_continuation);&#125; reactor.start_op()很长，截取重点如下，其会根据传入的op_type(read_op = 0, write_op = 1,connect_op = 1, except_op = 2)做一些event的监听事件的epoll_mod，然后把operation（就是传入的回调）放入当前的描述符的op_type下标对应的数组中,用于触发的时候去运行。 12345678910111213141516171819202122232425262728293031void epoll_reactor::start_op(int op_type, socket_type descriptor, epoll_reactor::per_descriptor_data&amp; descriptor_data, reactor_op* op, bool is_continuation, bool allow_speculative)&#123; ... if (op_type == write_op) &#123; if ((descriptor_data-&gt;registered_events_ &amp; EPOLLOUT) == 0) &#123; epoll_event ev = &#123; 0, &#123; 0 &#125; &#125;; ev.events = descriptor_data-&gt;registered_events_ | EPOLLOUT; ev.data.ptr = descriptor_data; if (epoll_ctl(epoll_fd_, EPOLL_CTL_MOD, descriptor, &amp;ev) == 0) &#123; descriptor_data-&gt;registered_events_ |= ev.events; &#125; else &#123; op-&gt;ec_ = asio::error_code(errno, asio::error::get_system_category()); scheduler_.post_immediate_completion(op, is_continuation); return; &#125; &#125; &#125; ... descriptor_data-&gt;op_queue_[op_type].push(op); scheduler_.work_started();&#125; 这一小节整体看下来，差不多可以得到这样的关系acceptor-&gt;reacotr_socket_service-&gt;reactor。 第三部分是io_context.run()的时候如何进行epoll( )并处理事件的 从main开始进行io_context.run( ) 1234567891011121314151617181920212223int main(int argc, char* argv[])&#123; try &#123; if (argc != 2) &#123; std::cerr &lt;&lt; &quot;Usage: async_tcp_echo_server &lt;port&gt;
&quot;; return 1; &#125; asio::io_context io_context; server s(io_context, std::atoi(argv[1])); io_context.run(); //开始循环处理 &#125; catch (std::exception&amp; e) &#123; std::cerr &lt;&lt; &quot;Exception: &quot; &lt;&lt; e.what() &lt;&lt; &quot;
&quot;; &#125; return 0;&#125; 实际执行了impl_.run() 1234567io_context::count_type io_context::run()&#123; asio::error_code ec; count_type s = impl_.run(ec); asio::detail::throw_error(ec); return s;&#125; 其实际运行的是scheduler::run()，看到其中有一个for循环运行do_run_one()处理 123456789101112131415161718192021std::size_t scheduler::run(asio::error_code&amp; ec)&#123; ec = asio::error_code(); if (outstanding_work_ == 0) &#123; stop(); return 0; &#125; thread_info this_thread; this_thread.private_outstanding_work = 0; thread_call_stack::context ctx(this, this_thread); mutex::scoped_lock lock(mutex_); std::size_t n = 0; for (; do_run_one(lock, this_thread, ec); lock.lock()) //for循环处理 if (n != (std::numeric_limits&lt;std::size_t&gt;::max)()) ++n; return n;&#125; do_run_one( )比较长，但是很好理解，其从任务队列获取任务，然后判断是否为task，如果是则说明需要做一次epoll对去接收fd的事件回来进行处理，如果不是，则是回调任务，把任务对应的回调函数运行即可； 其次，可以看到当判断任务有多个的时候会执行wakeup_event_.unlock_and_signal_one(lock);去唤醒别的线程也来消费该任务队列，锁的管理上，在上面的for循环上，一直都加有锁，而下面真正获取了任务去执行的时候就会把锁给放掉，同时用task_cleanup这个RAII的类，在处理完任务之后把锁给加回来； 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859std::size_t scheduler::do_run_one(mutex::scoped_lock&amp; lock, scheduler::thread_info&amp; this_thread, const asio::error_code&amp; ec)&#123; while (!stopped_) &#123; if (!op_queue_.empty()) &#123; // Prepare to execute first handler from queue. operation* o = op_queue_.front(); //从任务队列中获取任务 op_queue_.pop(); bool more_handlers = (!op_queue_.empty()); if (o == &amp;task_operation_) // epoll任务的话, 进行一次epoll, &#123; task_interrupted_ = more_handlers; if (more_handlers &amp;&amp; !one_thread_) wakeup_event_.unlock_and_signal_one(lock);//唤醒其它线程 else lock.unlock(); task_cleanup on_exit = &#123; this, &amp;lock, &amp;this_thread &#125;; (void)on_exit; // Run the task. May throw an exception. Only block if the operation // queue is empty and we&#x27;re not polling, otherwise we want to return // as soon as possible. task_-&gt;run(more_handlers ? 0 : -1, this_thread.private_op_queue); &#125; else // 回调的话，进行回调 &#123; std::size_t task_result = o-&gt;task_result_; if (more_handlers &amp;&amp; !one_thread_) wake_one_thread_and_unlock(lock); else lock.unlock(); // Ensure the count of outstanding work is decremented on block exit. work_cleanup on_exit = &#123; this, &amp;lock, &amp;this_thread &#125;; (void)on_exit; // Complete the operation. May throw an exception. Deletes the object. o-&gt;complete(this, ec, task_result); //调用回调函数 this_thread.rethrow_pending_exception(); return 1; &#125; &#125; else &#123; wakeup_event_.clear(lock); wakeup_event_.wait(lock); &#125; &#125; return 0;&#125; 这里细看一下task-&gt;run( )进行epoll时是怎么收任务的，将epoll返回的event中的事件保存下来以传给回调函数处理事件（上面调用回调函数时候传递的task_result），把这个描述符数据（包含了回调和结果）放入任务队列；这里有一个疑惑，epoll_reactor::run()这个函数是没有做加锁操作的，可epoll fd是共享的，存在多个线程同时epoll()的问题需要做同步，不知道其怎么实现的 12345678910111213141516171819void epoll_reactor::run(long usec, op_queue&lt;operation&gt;&amp; ops)&#123; // Block on the epoll descriptor. epoll_event events[128]; int num_events = epoll_wait(epoll_fd_, events, 128, timeout); // Dispatch the waiting events. for (int i = 0; i &lt; num_events; ++i) &#123; ... void* ptr = events[i].data.ptr; descriptor_state* descriptor_data = static_cast&lt;descriptor_state*&gt;(ptr); descriptor_data-&gt;set_ready_events(events[i].events); // 保存事件 ops.push(descriptor_data); // 放入任务队列 ... &#125;&#125;
